function convertToUsername(inputStr) {
    inputStr = inputStr.trim();
    if (inputStr.startsWith("https://ngl.link/")) {
        try {
            const url = new URL(inputStr);
            if (url.hostname !== "ngl.link") {
                return null;
            }
            const username = url.pathname.replace("/", "");
            if (!username) {
                return null;
            }
            return username;
        } catch (error) {
            return null;
        }
    } else {
        if (!inputStr) {
            return null;
        }
        return inputStr;
    }
}


async function checkUserExists(username) {
    try {
        const response = await axios.get(`https://ngl.link/${username}`, {
            headers: {
                "User-Agent":
                    userAgents[Math.floor(Math.random() * userAgents.length)],
                Accept: "text/html",
            },
            timeout: 15000,
        });

        return !response.data.includes("Could not find user");
    } catch (error) {
        return false;
    }
}


function getRandomizedContent(baseContent, enableEmoji) {
    let content = baseContent;
    if (enableEmoji) {
        content += getRandomEmoji();
    }
    return content;
}


async function sendSingleMessage(username, content, deviceId, mixpanelStr) {
    
    let randomUserAgent;
    let now = Date.now();

    
    let attempts = 0;
    do {
        randomUserAgent =
            userAgents[Math.floor(Math.random() * userAgents.length)];
        const lastUsed = uaMap.get(randomUserAgent) || 0;

        
        if (now - lastUsed > UA_COOLDOWN || attempts > 10) {
            uaMap.set(randomUserAgent, now);
            break;
        }

        attempts++;
    } while (attempts < 20);

    
    const languages = [
        "vi-VN,vi;q=0.9,fr-FR;q=0.8,fr;q=0.7,en-US;q=0.6,en;q=0.5",
        "en-US,en;q=0.9",
        "en-GB,en;q=0.9,en-US;q=0.8",
        "vi-VN,vi;q=0.9,en-US;q=0.8,en;q=0.7",
        "fr-FR,fr;q=0.9,en;q=0.8",
        "de-DE,de;q=0.9,en;q=0.8",
        "ja-JP,ja;q=0.9,en;q=0.8",
    ];

    const headers = {
        Accept: "*/*",
        "Accept-Encoding": "gzip, deflate, br, zstd",
        "Accept-Language":
            languages[Math.floor(Math.random() * languages.length)],
        Connection: Math.random() > 0.2 ? "keep-alive" : "close",
        "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8",
        Cookie: `_ga=GA1.1.${Math.floor(Math.random() * 9000000000) + 1000000000}.${Math.floor(Math.random() * 9000000000) + 1000000000}; mp_${randomString(32)}_mixpanel=${mixpanelStr}`,
        Host: "ngl.link",
        Origin: "https://ngl.link",
        Referer: `https://ngl.link/${username}`,
        "sec-ch-ua":
            '"Chromium";v="136", "Google Chrome";v="136", "Not.A/Brand";v="99"',
        "sec-ch-ua-mobile": Math.random() > 0.7 ? "?1" : "?0",
        "sec-ch-ua-platform": [
            '"Windows"',
            '"macOS"',
            '"Android"',
            '"iOS"',
            '"Linux"',
        ][Math.floor(Math.random() * 5)],
        "Sec-Fetch-Dest": "empty",
        "Sec-Fetch-Mode": "cors",
        "Sec-Fetch-Site": "same-origin",
        "User-Agent": randomUserAgent,
        "X-Requested-With": "XMLHttpRequest",
        "Cache-Control": Math.random() > 0.5 ? "no-cache" : "max-age=0",
        Pragma: Math.random() > 0.5 ? "no-cache" : "",
        Priority: ["high", "low", "auto"][Math.floor(Math.random() * 3)],
    };

    
    const data = {
        username: username,
        question: content,
        deviceId: deviceId,
        gameSlug: "",
        referrer: "",
        lang: Math.random() > 0.5 ? "en" : "vi",
    };

    
    const formData = new URLSearchParams(data).toString();

    try {
        const response = await axios.post(
            "https://ngl.link/api/submit",
            formData,
            {
                headers,
                timeout: 15000, 
            },
        );

        return { success: true, status: response.status };
    } catch (error) {
        if (error.response && error.response.status === 429) {
            
            uaMap.set(randomUserAgent, now + 30000); 
        }

        return {
            success: false,
            error: error.message,
            status: error.response ? error.response.status : null,
        };
    }
}


